company_id = env.company.id
# prepare removes
models_list = ['res.partner.bank','account.move.line','account.invoice','account.payment','account.bank.statement','account.tax.account.tag','account.tax','account.account.account.tag','wizard_multi_charts_accounts','account.journal','account.account']
try:
    # find field ids for product.template taxes
    try:
        field1 = env['ir.model.fields']._get('product.template', 'taxes_id').id
        field2 = env['ir.model.fields']._get('product.template', 'supplier_taxes_id').id
    except Exception:
        field1 = None
        field2 = None
    if field1 and field2:
        sql = "delete from ir_default where (field_id = %s or field_id = %s) and company_id=%d" % (field1, field2, company_id)
        sql2 = "update account_journal set bank_account_id=NULL where company_id=%d;" % company_id
        try:
            env.cr.execute(sql)
            env.cr.execute(sql2)
            try:
                env.cr.commit()
            except Exception:
                pass
        except Exception as e:
            _logger.error('remove data error: %s,%s', 'account_chart: set tax and account_journal', e)
except Exception as e:
    _logger.error('remove data error: %s,%s', 'account_chart', e)
# pos.config journal reset
if env['ir.model']._get('pos.config'):
    try:
        env['pos.config'].write({'journal_id': False})
    except Exception:
        pass
# reset partner properties
try:
    recs = env['res.partner'].search([])
    for r in recs:
        try:
            r.write({'property_account_receivable_id': None,'property_account_payable_id': None})
        except Exception:
            pass
except Exception as e:
    _logger.error('remove data error: %s,%s', 'account_chart', e)
# reset product category properties
try:
    recs = env['product.category'].search([])
    for r in recs:
        try:
            r.write({
                'property_account_income_categ_id': None,
                'property_account_expense_categ_id': None,
                'property_account_creditor_price_difference_categ': None,
                'property_stock_account_input_categ_id': None,
                'property_stock_account_output_categ_id': None,
                'property_stock_valuation_account_id': None,
            })
        except Exception:
            pass
except Exception:
    pass
# reset product template properties
try:
    recs = env['product.template'].search([])
    for r in recs:
        try:
            r.write({'property_account_income_id': None,'property_account_expense_id': None})
        except Exception:
            pass
except Exception:
    pass
# reset stock location valuation accounts
try:
    recs = env['stock.location'].search([])
    for r in recs:
        try:
            r.write({'valuation_in_account_id': None,'valuation_out_account_id': None})
        except Exception:
            pass
except Exception:
    pass
# finally remove models via delete
for m in models_list:
    try:
        if not env['ir.model']._get(m):
            continue
    except Exception:
        continue
    try:
        t = env['ir.model']._get(m)
        table = t.model.replace('.', '_')
    except Exception:
        table = m.replace('.', '_')
    try:
        env.cr.execute('delete from %s' % table)
        try:
            env.cr.commit()
        except Exception:
            pass
    except Exception as e:
        _logger.error('remove data error: %s,%s', m, e)
# return True

