def _remove_data(env, models_list, seqs_list):
    for line in models_list:
        try:
            if not env['ir.model']._get(line):
                continue
        except Exception as e:
            _logger.warning('remove data error get ir.model: %s,%s', line, e)
            continue
        obj_name = line
        try:
            obj = env.registry.models.get(obj_name)
        except Exception:
            obj = None
        if not obj:
            t_name = obj_name.replace('.', '_')
        else:
            # try to get table name via ir.model._get
            try:
                t = env['ir.model']._get(obj_name)
                t_name = t.model.replace('.', '_')
            except Exception:
                t_name = obj_name.replace('.', '_')
        sql = "delete from %s" % t_name
        try:
            env.cr.execute(sql)
            try:
                env.cr.commit()
            except Exception:
                # commit might be restricted on SaaS, ignore if fails
                pass
        except Exception as e:
            _logger.warning('remove data error: %s,%s', line, e)
    for line in seqs_list:
        domain = ['|', ('code', '=ilike', line + '%'), ('prefix', '=ilike', line + '%')]
        try:
            seqs = env['ir.sequence'].sudo().search(domain)
            if seqs.exists():
                seqs.write({'number_next': 1})
        except Exception as e:
            _logger.warning('reset sequence data error: %s,%s', line, e)
    return True

_remove_data(env, ['mail.message','mail.followers','mail.activity'], [])

